String _resolveBillingFlowLabel(AppEnvironment environment) {
  return _isRegionalExternalBillingExceptionEnabled(environment)
      ? 'regional_exception_enabled'
      : 'store_billing_default';
}

bool _isRegionalExternalBillingExceptionEnabled(AppEnvironment environment) {
  return environment.isExternalBillingExceptionActive;
}

Uri _resolvePaywallManageUri(AppEnvironment environment) {
  if (_isRegionalExternalBillingExceptionEnabled(environment)) {
    final customUrl = environment.externalBillingManageUrl;
    if (customUrl != null) {
      return Uri.parse(customUrl);
    }
  }
  return defaultTargetPlatform == TargetPlatform.iOS
      ? Uri.parse(_iosManageSubscriptionUrl)
      : Uri.parse(_androidManageSubscriptionUrl);
}

Future<String> _bootstrapCurrentProfile({String? preferredRole}) async {
  final user = FirebaseAuth.instance.currentUser;
  if (user == null) {
    await _driverPushTokenRegistrationService.dispose();
    return 'unknown';
  }

  // Force a fresh ID token before role bootstrap to avoid stale provider claims
  // after account switch / guest transitions.
  try {
    await user.getIdToken(true);
  } catch (_) {
    // Best effort only; callable still runs with current auth context.
  }

  final result = await BootstrapUserProfileClient(
    functions: FirebaseFunctions.instanceFor(region: firebaseFunctionsRegion),
  ).bootstrap(
    BootstrapUserProfileInput(
      displayName: _resolveDisplayName(user),
      preferredRole: _resolveAuthNextRole(preferredRole),
    ),
  );
  final role = result.role.name;
  if (role == 'driver') {
    try {
      await _registerDevice(user);
    } on FirebaseFunctionsException catch (error) {
      debugPrint('registerDevice skipped (${error.code}).');
    } catch (_) {
      debugPrint('registerDevice skipped (unknown).');
    }
  } else {
    await _driverPushTokenRegistrationService.dispose();
  }
  return role;
}

Future<String> _promoteToDriverRoleWithRetry() async {
  var role = await _bootstrapCurrentProfile(preferredRole: _authNextRoleDriver);
  if (role == 'driver') {
    return role;
  }

  final user = FirebaseAuth.instance.currentUser;
  if (user == null) {
    return role;
  }
  try {
    await user.reload();
    await user.getIdToken(true);
  } catch (_) {
    // Continue with a second best-effort bootstrap attempt.
  }
  role = await _bootstrapCurrentProfile(preferredRole: _authNextRoleDriver);
  return role;
}

Future<void> _registerDevice(User user) async {
  await _driverPushTokenRegistrationService.registerForUid(user.uid);
}

Future<void> _subscribePassengerRouteTopic(String routeId) async {
  try {
    await _routeTopicSubscriptionService.subscribeRouteTopic(routeId);
  } catch (error) {
    debugPrint('route topic subscribe skipped ($routeId): $error');
  }
}

Future<void> _unsubscribePassengerRouteTopic(String routeId) async {
  try {
    await _routeTopicSubscriptionService.unsubscribeRouteTopic(routeId);
  } catch (error) {
    debugPrint('route topic unsubscribe skipped ($routeId): $error');
  }
}

Future<UserRole> _resolveCurrentUserRole(String uid) async {
  return ReadUserRoleUseCase(
    repository: FirestoreUserRoleRepository(),
  ).execute(uid);
}
